mapper.select:
SELECT e.id AS id, e.yonghu_id AS yonghuId, s.name AS studentname, e.exampaper_id AS exampaperId, p.exampaper_name AS exampaperName, e.total_score AS totalScore, e.insert_time AS insertTime, e.create_time AS createTime FROM ( -- 子查询：获取每个学生每门考试的最新记录 SELECT *, ROW_NUMBER() OVER (PARTITION BY yonghu_id, exampaper_id ORDER BY insert_time DESC) as rn FROM examrecord WHERE total_score IS NOT NULL AND total_score > 0 ) e LEFT JOIN student s ON e.yonghu_id = s.id LEFT JOIN exampaper p ON e.exampaper_id = p.id WHERE e.rn = 1 -- 只保留最新的记录 AND e.total_score IS NOT NULL AND s.id IS NOT NULL -- 确保学生信息存在
AND ${ew.sqlSegment}
ORDER BY e.insert_time DESC

        SELECT
        
        
        ,exampaper.exampaper_name as exampaperName
        ,exampaper.exampaper_date as exampaperDate
        ,exampaper.exampaper_myscore as exampaperMyscore

        ,exampaper.exampaper_types as exampaperTypes
        ,exampaper.zujuan_types as zujuanTypes
        ,exampaper.exampaper_delete as exampaperDelete
        ,yonghu.name as studentname
        ,yonghu.phone as shoujihaoma

        ,yonghu.profile as xiangpian
        ,yonghu.level as youxiang

        FROM examrecord  a
        left JOIN exampaper exampaper ON a.exampaper_id = exampaper.id
        left JOIN student yonghu ON a.yonghu_id = yonghu.id

        
            
                and a.id in
                
                #{item}
                
            
            
                and a.examrecord_uuid_number like CONCAT('%',#{params.examrecordUuidNumber},'%')
            
            
                and (
                    a.yonghu_id = #{params.yonghuId}
                )
            
            
                and (
                    a.exampaper_id = #{params.exampaperId}
                )
            
            
                  and a.total_score >= #{params.totalScoreStart}   
            
            
                  and a.total_score <= #{params.totalScoreEnd}   
            
             
                and a.total_score = #{params.totalScore}
             
            
                  and UNIX_TIMESTAMP(a.insert_time) >= UNIX_TIMESTAMP(#{params.insertTimeStart}) 
            
            
                  and UNIX_TIMESTAMP(a.insert_time) <= UNIX_TIMESTAMP(#{params.insertTimeEnd}) 
            

                
            
                and a.exampaper_id IS NOT NULL
            
            
                and exampaper.exampaper_name like CONCAT('%',#{params.exampaperName},'%')
            
            
                  and exampaper.exampaper_date >= #{params.exampaperDateStart}   
            
            
                  and exampaper.exampaper_date <= #{params.exampaperDateEnd}   
            
            
                and exampaper.exampaper_date = #{params.exampaperDate}
            
            
                  and exampaper.exampaper_myscore >= #{params.exampaperMyscoreStart}   
            
            
                  and exampaper.exampaper_myscore <= #{params.exampaperMyscoreEnd}   
            
            
                and exampaper.exampaper_myscore = #{params.exampaperMyscore}
            


            
                and exampaper.exampaper_types = #{params.exampaperTypes}
            

            
                and exampaper.zujuan_types = #{params.zujuanTypes}
            

            
                  and exampaper.exampaper_delete >= #{params.exampaperDeleteStart}   
            
            
                  and exampaper.exampaper_delete <= #{params.exampaperDeleteEnd}   
            
            
                and exampaper.exampaper_delete = #{params.exampaperDelete}
            
                
            
                and a.yonghu_id IS NOT NULL
            
            
                and yonghu.studentname like CONCAT('%',#{params.studentname},'%')
            
            
                and yonghu.shoujihaoma like CONCAT('%',#{params.shoujihaoma},'%')
            

            
                and yonghu.youxiang like CONCAT('%',#{params.youxiang},'%')
            
        
        order by a.${params.sort} ${params.order}
